import React, { useState, useEffect } from "react";
import axios from "axios";
import Grid from "@material-ui/core/Grid";

import Today from "./PolandComponents/Today";
import Total from "./PolandComponents/Total";

let intervalId = null;

const Poland = () => {
  //const [timeline, setTimeline] = useState([]);
  const [stats, setStats] = useState({
    todayNew: 0,
    todayDeaths: 0,
    todayRecovered: 0,
    totalConfirmed: 0,
    totalDeaths: 0,
    totalRecovered: 0
  });
  useEffect(() => {
    axios
      .get("https://corona-api.com/countries/PL")
      .then(res => {
        setStats({
          todayNew: res.data.data.today.confirmed || 0,
          todayDeaths: res.data.data.today.deaths || 0,
          todayRecovered: res.data.data.today.recovered || 0,
          totalConfirmed: res.data.data.latest_data.confirmed || 0,
          totalDeaths: res.data.data.latest_data.deaths || 0,
          totalRecovered: res.data.data.latest_data.recovered || 0
        });
        //setTimeline(res.data.data.timeline);
      })
      .catch(err => {
        console.error(err);
      });

    intervalId = setInterval(() => {
      axios.get("https://corona-api.com/countries/PL").then(res => {
        if (res.data.data.today.confirmed !== stats.todayNew) {
          setStats({ todayNew: res.data.data.today.confirmed });
        }
        if (res.data.data.today.deaths !== stats.todayDeaths) {
          setStats({ todayDeaths: res.data.data.today.deaths });
        }
        if (res.data.data.today.recovered !== stats.todayRecovered) {
          setStats({ todayRecovered: res.data.data.today.recovered });
        }
        if (res.data.data.latest_data.confirmed !== stats.totalConfirmed) {
          setStats({ totalConfirmed: res.data.data.latest_data.confirmed });
        }
        if (res.data.data.latest_data.confirmed.deaths !== stats.totalDeaths) {
          setStats({ totalDeaths: res.data.data.latest_data.deaths });
        }
        if (
          res.data.data.latest_data.confirmed.recovered !== stats.totalRecovered
        ) {
          setStats({ totalRecovered: res.data.data.latest_data.recovered });
        }
      });
    }, 300000);
    return () => {
      clearInterval(intervalId);
    };
  }, [stats]);
  return (
    <Grid container>
      <Grid item xs={12} md={8}>
        <Today stats={stats} />
      </Grid>
      <Grid item xs={12} md={4}>
        <Total stats={stats} />
      </Grid>
    </Grid>
  );
};

export default Poland;
